<?php
namespace App\Livewire\Billing\Cashier;
use App\Models\CashierSession; use App\Services\CashierSessionService; use Illuminate\Support\Facades\Gate; use Livewire\Component; use Livewire\WithPagination; use Masmerise\Toaster\Toaster as Notifier;
class Sessions extends Component { use WithPagination; public bool $showOpen=false; public bool $showClose=false; public string $opening_float='0'; public string $declared_cash='0'; public ?string $notes=null; public function mount(): void { Gate::authorize('cashier.sessions.view'); } public function open(CashierSessionService $service): void { Gate::authorize('cashier.sessions.open'); $this->validate(['opening_float'=>['required','numeric','min:0']]); $service->openSession(auth()->user(),(float)$this->opening_float,$this->notes); $this->showOpen=false; Notifier::success('cashier.session_opened'); } public function close(CashierSessionService $service): void { Gate::authorize('cashier.sessions.close'); $session=$service->getActiveSession(auth()->user()); if($session){$service->closeSession($session,(float)$this->declared_cash,$this->notes,auth()->user());} $this->showClose=false; Notifier::success('cashier.session_closed'); } public function closeModal(): void { $this->showOpen=false; $this->showClose=false; } public function render(){ return view('livewire.billing.cashier.sessions',['sessions'=>CashierSession::query()->forCurrentFacility()->when(!auth()->user()->can('cashier.sessions.view-all'),fn($q)=>$q->where('user_id',auth()->id()))->latest()->paginate(12)])->layout('components.layouts.app',['title'=>'Cashier Sessions','description'=>'Open, close and review cashier sessions.']); } }
